mapper.select:
SELECT COUNT(*) AS total FROM video_total vt
AND vt.user_id IN (SELECT u.id FROM `user` u LEFT JOIN user_class uc ON u.id = uc.user_id WHERE uc.class_id = #{classId})
AND vt.user_id = #{userId}

SELECT u.user_name AS userName, co.course_name AS courseName,
FROM video_total vt LEFT JOIN `user` u ON u.id = vt.user_id LEFT JOIN user_class uc ON uc.user_id = vt.user_id LEFT JOIN class c ON c.id = uc.class_id LEFT JOIN course co ON co.id = c.course_id
AND uc.class_id = #{classId}
AND vt.user_id = #{userId}
ORDER BY vt.id DESC LIMIT #{page},#{pageSize}
